class SecretBox:
    def __init__(self):
        self.contents = [10, 20, 30]

    def __getitem__(self, index):
        return self.contents[index] * 2

box = SecretBox()
print(box[1])

class Bag:
    def __init__(self, items):
        self.items = items

    def __len__(self):
        return str(len(self.items))

bag = Bag(['apple', 'banana'])
print(len(bag))
